## 💻 서버 코드 예시

### Express.js에서 적절한 코드 반환

```javascript
const express = require('express');
const app = express();

app.post('/api/users', async (req, res) => {
  try {
    const { name, email } = req.body;

    // 400 Bad Request (필수 필드 없음)
    if (!name || !email) {
      return res.status(400).json({
        error: 'name and email are required'
      });
    }

    // 409 Conflict (이미 존재)
    const exists = await db.findUserByEmail(email);
    if (exists) {
      return res.status(409).json({
        error: 'User with this email already exists'
      });
    }

    // 201 Created (성공)
    const user = await db.createUser({ name, email });
    return res.status(201).json(user);

  } catch (error) {
    // 500 Internal Server Error
    console.error('Error creating user:', error);
    return res.status(500).json({
      error: 'Internal server error'
    });
  }
});

app.get('/api/users/:id', async (req, res) => {
  const user = await db.findUser(req.params.id);

  // 404 Not Found
  if (!user) {
    return res.status(404).json({
      error: 'User not found'
    });
  }

  // 200 OK
  return res.status(200).json(user);
});

app.delete('/api/users/:id', async (req, res) => {
  // 401 Unauthorized (인증 필요)
  if (!req.headers.authorization) {
    return res.status(401).json({
      error: 'Authentication required'
    });
  }

  // 403 Forbidden (권한 없음)
  if (req.user.role !== 'admin') {
    return res.status(403).json({
      error: 'Admin access required'
    });
  }

  await db.deleteUser(req.params.id);

  // 204 No Content (삭제 성공, 반환 데이터 없음)
  return res.status(204).send();
});
```

## 🖥️ 클라이언트 코드 예시

### 상태 코드별 처리

```javascript
async function fetchUserData(userId) {
  try {
    const response = await fetch(`/api/users/${userId}`, {
      headers: {
        'Authorization': `Bearer ${token}`
      }
    });

    // 상태 코드별 분기 처리
    switch (response.status) {
      case 200:
        // 성공
        const data = await response.json();
        return data;

      case 401:
        // 인증 필요 → 로그인 페이지로
        alert('로그인이 필요합니다');
        window.location.href = '/login';
        break;

      case 403:
        // 권한 없음
        alert('이 데이터에 접근할 권한이 없습니다');
        break;

      case 404:
        // 데이터 없음
        alert('사용자를 찾을 수 없습니다');
        break;

      case 429:
        // Rate Limit 초과
        const retryAfter = response.headers.get('Retry-After');
        alert(`요청이 너무 많습니다. ${retryAfter}초 후 다시 시도하세요`);
        break;

      case 500:
      case 502:
      case 503:
        // 서버 오류
        alert('서버 오류가 발생했습니다. 잠시 후 다시 시도하세요');
        break;

      default:
        alert(`알 수 없는 오류: ${response.status}`);
    }

  } catch (error) {
    // 네트워크 오류 (응답 자체가 없음)
    console.error('Network error:', error);
    alert('네트워크 연결을 확인하세요');
  }
}

// response.ok 활용 (200~299 체크)
async function simpleFetch(url) {
  const response = await fetch(url);

  if (!response.ok) {
    // 200번대가 아니면 에러
    throw new Error(`HTTP error: ${response.status}`);
  }

  return response.json();
}
```

